import{_ as t,o as i,c as n,a2 as e}from"./chunks/framework.CHeM0PsO.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"gm/sdm-evaluasi.md","filePath":"gm/sdm-evaluasi.md","lastUpdated":1784467494000}'),r={name:"gm/sdm-evaluasi.md"};function s(o,a,d,l,u,g){return i(),n("div",null,[...a[0]||(a[0]=[e('<h2 id="bab-9-dashboard-tab-3-—-sdm-evaluasi" tabindex="-1">BAB 9: DASHBOARD TAB 3 — SDM &amp; EVALUASI <a class="header-anchor" href="#bab-9-dashboard-tab-3-—-sdm-evaluasi" aria-label="Permalink to &quot;BAB 9: DASHBOARD TAB 3 — SDM &amp; EVALUASI&quot;">​</a></h2><p>Tab ini menggantikan rutinitas meeting bulanan. Anda bisa langsung melihat siapa SPV yang berkinerja baik dan siapa yang perlu dievaluasi.</p><blockquote><p><strong>Catatan:</strong> Beberapa bagian di tab ini otomatis <strong>disembunyikan</strong> jika Anda sedang di Mode Strategis (&gt;95 hari). Ini disengaja agar data tahunan tidak terdistorsi oleh pergantian staf.</p></blockquote><h3 id="_9-1-kesehatan-tim-aset" tabindex="-1">9.1 Kesehatan Tim &amp; Aset <a class="header-anchor" href="#_9-1-kesehatan-tim-aset" aria-label="Permalink to &quot;9.1 Kesehatan Tim &amp; Aset&quot;">​</a></h3><p>4 indikator kesehatan tim:</p><table tabindex="0"><thead><tr><th>Indikator</th><th>Sumber Data</th><th>Catatan</th></tr></thead><tbody><tr><td>SOP Keramahan Staf (%)</td><td>Rata-rata dari laporan harian</td><td>Warna berubah sesuai persentase</td></tr><tr><td>Total Telat</td><td>Hitungan dari database kehadiran</td><td>Berubah merah jika sering</td></tr><tr><td>Teguran (SP)</td><td>Dari laporan bulanan SPV</td><td>—</td></tr><tr><td>Turnover</td><td>Dari laporan bulanan SPV</td><td>—</td></tr></tbody></table><h3 id="_9-2-cash-discrepancy-fingerprint-minus-kas" tabindex="-1">9.2 Cash Discrepancy Fingerprint (Minus Kas) <a class="header-anchor" href="#_9-2-cash-discrepancy-fingerprint-minus-kas" aria-label="Permalink to &quot;9.2 Cash Discrepancy Fingerprint (Minus Kas)&quot;">​</a></h3><blockquote><p>Hanya muncul di Mode Taktis (&lt; 95 hari).</p></blockquote><p>Jika sering terjadi uang kas minus, sistem menghitung <strong>frekuensi kehadiran setiap staf</strong> pada hari-hari saat kas minus terjadi. Hasilnya ditampilkan sebagai grafik batang:</p><ul><li>Jika satu nama menjulang tinggi, itu adalah <strong>indikator potensi evaluasi</strong> (bukan tuduhan langsung — lihat BAB 10 untuk penjelasan algoritma)</li><li>Contoh: &quot;Total Minus Rp 200.000. Terjadi saat Amel bertugas 26 kali, Eko 17 kali&quot;</li></ul><h3 id="_9-3-revenue-per-spv-shift-leaderboard" tabindex="-1">9.3 Revenue Per SPV Shift (Leaderboard) <a class="header-anchor" href="#_9-3-revenue-per-spv-shift-leaderboard" aria-label="Permalink to &quot;9.3 Revenue Per SPV Shift (Leaderboard)&quot;">​</a></h3><p>Menghitung rata-rata omset per shift jaga tiap SPV:</p><ul><li>Membedakan secara nyata mana SPV yang hanya bisa mengatur jadwal, dan mana SPV yang pandai menjual (upselling)</li></ul><h3 id="_9-4-dominasi-topik-briefing-spv" tabindex="-1">9.4 Dominasi Topik Briefing SPV <a class="header-anchor" href="#_9-4-dominasi-topik-briefing-spv" aria-label="Permalink to &quot;9.4 Dominasi Topik Briefing SPV&quot;">​</a></h3><p>Sistem menghitung kata kunci yang paling sering muncul di topik briefing SPV:</p><ul><li>Contoh: kata &quot;Bersih&quot; sering disebut, tapi skor kebersihan tetap buruk → <strong>&quot;Eksekusi di lapangan lemah&quot;</strong></li></ul><h3 id="_9-5-pandangan-ke-depan-evaluasi-spv" tabindex="-1">9.5 Pandangan Ke Depan &amp; Evaluasi SPV <a class="header-anchor" href="#_9-5-pandangan-ke-depan-evaluasi-spv" aria-label="Permalink to &quot;9.5 Pandangan Ke Depan &amp; Evaluasi SPV&quot;">​</a></h3><p>Berisi isi pikiran SPV dari laporan bulanan mereka:</p><ul><li><strong>Strategi Bulan Depan</strong> yang direncakanan SPV</li><li><strong>Kebutuhan Approval GM</strong> — apa yang mereka minta dari Anda</li><li><strong>Pencapaian Terbaik &amp; Tantangan Tersulit</strong> — kejujuran dari lapangan</li></ul><h3 id="_9-6-arsip-laporan-pdf" tabindex="-1">9.6 Arsip Laporan PDF <a class="header-anchor" href="#_9-6-arsip-laporan-pdf" aria-label="Permalink to &quot;9.6 Arsip Laporan PDF&quot;">​</a></h3><p>Menu accordion di bagian paling bawah Dashboard. Berisi daftar historis semua PDF laporan yang pernah dikirim SPV:</p><table tabindex="0"><thead><tr><th>Kolom</th><th>Fungsi</th></tr></thead><tbody><tr><td>Judul &amp; Tanggal Upload</td><td>Nama file dan waktu submit</td></tr><tr><td>Tombol PDF</td><td>Klik untuk membuka atau mengunduh PDF dari Google Drive</td></tr></tbody></table><hr><h3 id="_9-7-marketing-intelligence-tab-1-—-bagian-bawah" tabindex="-1">9.7 Marketing Intelligence (Tab 1 — Bagian Bawah) <a class="header-anchor" href="#_9-7-marketing-intelligence-tab-1-—-bagian-bawah" aria-label="Permalink to &quot;9.7 Marketing Intelligence (Tab 1 — Bagian Bawah)&quot;">​</a></h3><p>Modul analisis lanjutan yang dipicu dengan tombol <strong>&quot;Simpan &amp; Tarik Analisis&quot;</strong>. Terdapat pengaturan <strong>Benchmark ATS</strong> (default Rp 30.000) yang bisa Anda ubah.</p><p>Setelah tombol ditekan, muncul 5 modul dalam bentuk kotak lipatan (<em>accordion</em>):</p><table tabindex="0"><thead><tr><th>Modul</th><th>Diagram</th><th>Cara Membaca</th></tr></thead><tbody><tr><td><strong>Tren Omset</strong></td><td>Bar Chart Hitam</td><td>Hijau jika naik ≥5%, Merah jika turun ≤-5%, Kuning jika stagnan</td></tr><tr><td><strong>Korelasi Kebersihan &amp; Omset</strong></td><td>Dual-Axis Chart (Garis + Bar)</td><td>&quot;The Perfect Storm&quot; = Ramai tapi kotor. &quot;The Lazy Shift&quot; = Sepi dan kotor</td></tr><tr><td><strong>SDM &amp; Risiko Operasional</strong></td><td>Donut Chart (Pie Berlubang)</td><td>Hijau = Tepat Waktu, Merah = Terlambat, Abu = Izin/Alpha</td></tr><tr><td><strong>Benchmarking ATS</strong></td><td>Bar Horizontal (Aktual vs Target)</td><td>Melebihi benchmark = upselling berhasil</td></tr><tr><td><strong>Analisis Menu</strong></td><td>Bar Horizontal (Hijau = Hero, Oranye = Dead)</td><td>Produk konsisten terlaris vs produk konsisten mati</td></tr></tbody></table><p>Di bawah 5 modul ini juga terdapat ringkasan:</p><ul><li><strong>Profil Pengunjung Mayoritas</strong> — misal: &quot;Mahasiswa Nugas&quot;</li><li><strong>Kondisi/Event Dominan</strong> — misal: &quot;Cuaca Hujan/Badai (60%)&quot;</li></ul><h3 id="_9-8-analisis-performa-produk-kinerja-kategori" tabindex="-1">9.8 Analisis Performa Produk (Kinerja Kategori) <a class="header-anchor" href="#_9-8-analisis-performa-produk-kinerja-kategori" aria-label="Permalink to &quot;9.8 Analisis Performa Produk (Kinerja Kategori)&quot;">​</a></h3><p>Accordion terpisah yang membedah kinerja produk per kategori secara detail:</p><ul><li><strong>Top 5</strong> produk paling laku per kategori</li><li><strong>Bottom 3</strong> produk paling tidak laku</li><li><strong>Action Plan</strong> yang diketik SPV untuk setiap produk mati</li></ul><hr>',33)])])}const m=t(r,[["render",s]]);export{h as __pageData,m as default};
